-- ─── 3. Wzorce projektowe (40 cards) ────────────────────────────────────────
DO $$
DECLARE v_set_id integer;
BEGIN

VALUES ('00000000-0000-0000-0000-000000000001', 'Wzorce projektowe', 'Najważniejsze wzorce projektowe: kreacyjne, strukturalne i behawioralne', '{"programming","design-patterns","architecture","it"}', true, now(), now(), now())
RETURNING id INTO v_set_id;

-- Kreacyjne (Creational)
('Singleton', 'Zapewnia, że klasa ma dokładnie jedną instancję i udostępnia do niej globalny punkt dostępu. Stosuj: globalna konfiguracja, połączenie z bazą danych, logger.', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Factory Method', 'Definiuje interfejs tworzenia obiektów, ale pozwala podklasom decydować, która klasa zostanie utworzona. Stosuj gdy nie znasz z góry typu obiektu do stworzenia.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Abstract Factory', 'Interfejs do tworzenia rodzin powiązanych obiektów bez specyfikowania ich klas. Stosuj gdy system musi obsługiwać wiele wariantów produktów (np. UI dla różnych systemów).', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Builder', 'Oddziela konstrukcję złożonego obiektu od jego reprezentacji. Pozwala tworzyć różne warianty krok po kroku. Stosuj gdy obiekt ma wiele opcjonalnych parametrów.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Prototype', 'Tworzy nowe obiekty przez klonowanie istniejącego prototypu. Unika kosztownej inicjalizacji. Stosuj gdy tworzenie obiektu od zera jest drogie, a kopia wystarczy.', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
-- Strukturalne (Structural)
('Adapter', 'Konwertuje interfejs klasy na inny interfejs oczekiwany przez klienta. Pozwala współpracować klasom o niekompatybilnych interfejsach. Stosuj przy integracji legacy kodu.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Bridge', 'Oddziela abstrakcję od implementacji, by mogły zmieniać się niezależnie. Stosuj gdy masz wiele wymiarów zmienności (np. kształt × kolor × renderer).', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Composite', 'Składa obiekty w struktury drzewiaste, by traktować pojedyncze obiekty i kompozycje jednakowo. Stosuj do reprezentowania hierarchii część-całość (np. menu, system plików).', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Decorator', 'Dynamicznie dodaje nowe zachowanie do obiektu, opakowując go. Alternatywa dla dziedziczenia. Stosuj gdy potrzebujesz elastycznego rozszerzania funkcjonalności (np. middleware, strumienie I/O).', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Facade', 'Uproszczony interfejs do złożonego podsystemu. Nie ukrywa podsystemu, ale ułatwia jego użycie. Stosuj do zapewnienia prostego API dla skomplikowanej logiki.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Flyweight', 'Współdzieli wspólne dane między wieloma obiektami, by oszczędzać pamięć. Wydziela stan wewnętrzny (wspólny) i zewnętrzny (unikalny). Stosuj przy dużej liczbie podobnych obiektów (np. znaki w edytorze).', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Proxy', 'Obiekt zastępczy kontrolujący dostęp do innego obiektu. Rodzaje: wirtualny (lazy loading), ochronny (autoryzacja), zdalny (RPC). Stosuj do kontroli dostępu i leniwej inicjalizacji.', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
-- Behawioralne (Behavioral)
('Observer', 'Definiuje zależność jeden-do-wielu: gdy obiekt zmienia stan, wszystkie zależne są powiadamiane. Stosuj do systemów zdarzeń, reaktywnych UI, pub/sub.', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Strategy', 'Definiuje rodzinę algorytmów i umożliwia ich wymianę. Klient wybiera algorytm w runtime. Stosuj gdy masz wiele wariantów tego samego zachowania (np. sortowanie, walidacja).', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Command', 'Opakowuje żądanie jako obiekt z metodą execute(). Umożliwia: kolejkowanie, undo/redo, logowanie poleceń. Stosuj w menu, toolbar, systemach transakcyjnych.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Template Method', 'Definiuje szkielet algorytmu w klasie bazowej, pozwalając podklasom nadpisać wybrane kroki. Stosuj gdy kilka klas dzieli algorytm z różniącymi się szczegółami.', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Iterator', 'Zapewnia sekwencyjny dostęp do elementów kolekcji bez ujawniania jej struktury. Stosuj do zunifikowanego przechodzenia po różnych kolekcjach (lista, drzewo, graf).', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('State', 'Pozwala obiektowi zmieniać zachowanie, gdy zmienia się jego wewnętrzny stan. Eliminuje duże bloki if/switch. Stosuj do maszyn stanowych (np. zamówienie, połączenie sieciowe).', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Chain of Responsibility', 'Przekazuje żądanie wzdłuż łańcucha handlerów, aż jeden je obsłuży. Stosuj do middleware (Express, Angular interceptors), walidacji wieloetapowej, logowania.', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Mediator', 'Centralizuje komunikację między obiektami, by nie musiały znać się nawzajem. Zmniejsza liczbę powiązań. Stosuj do chat roomów, kontrolerów lotów, formularzy.', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Memento', 'Przechwytuje i eksternalizuje wewnętrzny stan obiektu, by móc go przywrócić później. Stosuj do funkcji undo/redo, zapisywania gier, snapshottów.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Visitor', 'Pozwala dodać nową operację do struktury obiektów bez modyfikacji ich klas. Stosuj gdy masz stabilną hierarchię, a operacje się zmieniają (np. analiza AST, eksport danych).', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Interpreter', 'Definiuje gramatykę języka i interpreter zdań tego języka. Stosuj do prostych DSL, wyrażeń regularnych, kalkulatorów. Mało używany w nowoczesnych aplikacjach.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
-- Dodatkowe popularne wzorce
('Repository', 'Pośredniczy między warstwą domeny a dostępem do danych. Udostępnia kolekcyjny interfejs (find, save, delete) ukrywając szczegóły bazy/API. Stosuj w architekturze wielowarstwowej.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Dependency Injection (DI)', 'Dostarcza zależności obiektowi z zewnątrz zamiast tworzyć je wewnątrz. Ułatwia testowanie i zmianę implementacji. Stosuj wszędzie — to fundament luźnego wiązania.', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('MVC (Model-View-Controller)', 'Dzieli aplikację na: Model (dane i logika), View (prezentacja), Controller (obsługa wejścia). Stosuj do aplikacji webowych i desktopowych z wyraźnym podziałem odpowiedzialności.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('MVVM (Model-View-ViewModel)', 'Wariant MVC: ViewModel eksponuje dane i komendy dla View przez binding. View nie zna Modelu bezpośrednio. Stosuj w Angular, WPF, SwiftUI — frameworkach z data binding.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Event Sourcing', 'Zamiast zapisywać bieżący stan, zapisuje sekwencję zdarzeń. Stan odtwarzany przez odtworzenie zdarzeń. Pełna historia zmian. Stosuj w systemach finansowych, auditach.', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('CQRS (Command Query Responsibility Segregation)', 'Oddziela model zapisu (Command) od modelu odczytu (Query). Pozwala optymalizować każdy niezależnie. Stosuj w złożonych systemach z różnymi wymaganiami odczytu i zapisu.', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Saga', 'Wzorzec zarządzania transakcjami rozproszonymi jako sekwencja lokalnych transakcji z kompensacjami. Stosuj w mikroserwisach, gdy ACID między serwisami jest niemożliwy.', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Circuit Breaker', 'Chroni system przed kaskadowym awarią wywołań do niestabilnego serwisu. Trzy stany: Closed (normalne), Open (blokuje), Half-Open (próbuje). Stosuj w mikroserwisach.', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Pub/Sub (Publish-Subscribe)', 'Wzorzec komunikacji asynchronicznej: wydawcy publikują wiadomości, subskrybenci odbierają te, które ich interesują. Luźne wiązanie. Stosuj w eventach, message brokerach (Kafka, RabbitMQ).', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Object Pool', 'Zarządza pulą gotowych obiektów do ponownego użycia zamiast tworzenia/niszczenia. Stosuj dla kosztownych obiektów: połączenia DB, wątki, obiekty graficzne.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Null Object', 'Obiekt reprezentujący „brak" z neutralnym zachowaniem zamiast null. Eliminuje sprawdzanie null w kodzie klienta. Stosuj gdy brak obiektu jest częstym, prawidłowym scenariuszem.', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Specification', 'Enkapsuluje reguły biznesowe jako obiekty z metodą isSatisfiedBy(). Reguły łączy się operatorami AND/OR/NOT. Stosuj do filtrowania, walidacji, wyszukiwania.', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Service Locator', 'Centralny rejestr dostarczający zależności na żądanie. Alternatywa dla DI, ale uznawana za antywzorzec — ukrywa zależności. Stosuj rzadko, preferuj DI.', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Data Transfer Object (DTO)', 'Prosty obiekt bez logiki biznesowej, używany do transferu danych między warstwami lub systemami. Stosuj w API — definiuje kształt danych żądania/odpowiedzi.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Lazy Initialization', 'Opóźnia tworzenie obiektu lub obliczenie do momentu pierwszego użycia. Oszczędza zasoby, jeśli obiekt może nie być potrzebny. Stosuj do ciężkich zasobów, konfiguracji.', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Strangler Fig', 'Wzorzec migracji: nowy system stopniowo przejmuje funkcjonalność starego, aż stary zostanie wyeliminowany. Stosuj przy modernizacji legacy — bezpieczna migracja krok po kroku.', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Anti-Corruption Layer', 'Warstwa tłumacząca między modelem domeny a zewnętrznym systemem o innym modelu danych. Chroni domenę przed „zanieczyszczeniem" obcymi konceptami. Stosuj przy integracji z legacy.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());

END $$;


